import pytest
from solution import parse_csv_line


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_simple_fields(self):
        """Basic comma-separated values without quotes."""
        assert parse_csv_line("a,b,c") == ["a", "b", "c"]

    def test_single_field(self):
        """A line with no commas returns a single-element list."""
        assert parse_csv_line("hello") == ["hello"]

    def test_numeric_fields(self):
        """Numeric strings are returned as strings."""
        assert parse_csv_line("1,2,3") == ["1", "2", "3"]

    def test_quoted_field_with_comma(self):
        """A comma inside quotes should NOT split the field."""
        assert parse_csv_line('"hello, world",foo') == ["hello, world", "foo"]

    def test_multiple_quoted_fields(self):
        """Multiple quoted fields are parsed correctly."""
        assert parse_csv_line('"a,b","c,d"') == ["a,b", "c,d"]

    def test_mixed_quoted_and_unquoted(self):
        """Mix of quoted and unquoted fields."""
        assert parse_csv_line('name,"John, Jr.",age') == ["name", "John, Jr.", "age"]

    def test_quoted_field_strips_quotes(self):
        """Quote characters themselves are removed from the result."""
        assert parse_csv_line('"hello"') == ["hello"]

    def test_whitespace_preserved(self):
        """Whitespace inside fields is preserved."""
        assert parse_csv_line("  a  , b , c  ") == ["  a  ", " b ", " c  "]

    def test_many_fields(self):
        """Works correctly with many fields."""
        line = ",".join(str(i) for i in range(10))
        assert parse_csv_line(line) == [str(i) for i in range(10)]


